// Patch v6 — La pastille "Fiche XX/YYYY" suit désormais l'état de
// confirmation (corail tant que non confirmé, sarcelle une fois confirmé)
// au lieu d'être toujours verte dès qu'un mois est renseigné — cohérence
// visuelle avec le reste de la carte.
//
// Usage : node patch_pausefigee_v6_badge_couleur.js
// À exécuter depuis : C:\Users\olive\Desktop\f2p-pmp
// PRÉREQUIS : avoir déjà exécuté patch_pausefigee_v5_reset_complet.js

const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'src', 'App.jsx');

const OLD_B64 = "";
const NEW_B64 = "";

const oldBlock = Buffer.from(OLD_B64, 'base64').toString('utf-8');
const newBlock = Buffer.from(NEW_B64, 'base64').toString('utf-8');

let content = fs.readFileSync(FILE).toString('utf-8');

const count = content.split(oldBlock).length - 1;
if (count === 0) throw new Error('[PauseFigeeSection v6] Ancre introuvable dans ' + FILE + ' — as-tu bien exécuté patch_pausefigee_v5_reset_complet.js avant celui-ci ?');
if (count > 1) throw new Error('[PauseFigeeSection v6] Ancre trouvée ' + count + ' fois (doit être unique) dans ' + FILE);

content = content.replace(oldBlock, newBlock);

fs.writeFileSync(FILE, content, 'utf-8');
console.log('OK — App.jsx patché (PauseFigeeSection v6 : pastille Fiche cohérente avec l\'état confirmé)');
